solutions.cpp:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void sortStack(vector<int>& stack) {
        sortRec(stack);
    }
private:
    void insertSorted(vector<int>& stack, int x) {
        if (stack.empty() || stack.back() <= x) {
            stack.push_back(x);
            return;
        }
        int top = stack.back();
        stack.pop_back();
        insertSorted(stack, x);
        stack.push_back(top);
    }
    void sortRec(vector<int>& stack) {
        if (stack.size() <= 1) return;
        int top = stack.back();
        stack.pop_back();
        sortRec(stack);
        insertSorted(stack, top);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> stack(n);
    for (int i = 0; i < n; ++i) cin >> stack[i];
    Solution sol;
    sol.sortStack(stack);
    for (int v : stack) {
        cout << v << "\n";
    }
    return 0;
}
